import config from './dbconfig.js';
import sql from 'mssql';
import CatchErrores from './modules/log-helper,js'

export default function getAll() {
    let pool = await sql.connect(config);
    let result = await pool.request().query("SELECT * from PIZZAS");

    console.log(result.recordset[0][0]);
}

export const getById = async (id) => {
    let pool = await sql.connect(config);
    let result = await pool.request().input('pId', sql.Int, id).query("SELECT * from PIZZAS WHERE Id = @pId");

    console.log(result.recordset[0][0]);


}

export const insert = async (id, nombre, descripcion, libreGluten, importe, descripcion) => {
    let pool = await sql.connect(config);
    let result = await pool.request()
        .input('pId', sql.Int, id, 'pNombre', sql.Varchar, nombre, 'pDescripcion', sql.Varchar, descripcion, 'plibreGluten', sql.Bool, libreGluten, 'pImporte', sql.Int, importe)
        .query("INSERT INTO PIZZAS (Id, Nombre, LibreGluten, Importe, Descripcion) VALUES (@pId, @pNombre, @pLibreGluten, @pImporte, @pDescripcion)");

    console.log(result.recordset[0][0]);
}

export const update = async (id, nombre, descripcion, libreGluten, importe, descripcion) => {
    let rowsAffected = 0;
    try {
        let pool = await sql.connect(config);
        let result = await pool.request()
            .input('pId', sql.Int, id, 'pNombre', sql.Varchar, nombre, 'pDescripcion', sql.Varchar, descripcion, 'plibreGluten', sql.Bool, libreGluten, 'pImporte', sql.Int, importe)
            .query("INSERT INTO PIZZAS (Id, Nombre, LibreGluten, Importe, Descripcion) VALUES (@pId, @pNombre, @pLibreGluten, @pImporte, @pDescripcion)");
        rowsAffected = result.rowsAffected;
    } catch (error) {
        CatchErrores(error);
        console.log(error);
    }
    return rowsAffected;
}

export const deleteById = async (id) => {
    let rowsAffected = 0;
    try {
        let pool = await sql.connect(config);
        let result = await pool.request().input('pId', sql.Int, id).query("Delete from PIZZAS WHERE Id = @pId");
        rowsAffected = result.rowsAffected;
    } catch (error) {
        CatchErrores(error);
        console.log(error);
    }
    console.log(result.recordset[0][0]);
}